package net.minestom.server.instance.block.property;

import org.jetbrains.annotations.ApiStatus;
import org.jetbrains.annotations.Contract;
import org.jetbrains.annotations.UnknownNullability;

/**
 * A property enum, associated with one or more properties in {@link Property}.
 * Only subsets of values may be valid for some blocks.
 * <p>
 * All implementations are autogenerated.
 */
@ApiStatus.NonExtendable
public interface PropertyEnum {
    /**
     * @return the string value associated with this enum constant.
     */
    @Contract(pure = true)
    String value();

    /**
     * A property enum associated with exactly one property in {@link Property}.
     * <p>
     * All implementations are autogenerated.
     */
    @ApiStatus.NonExtendable
    interface Keyed extends PropertyEnum {
        /**
         * @return the property this enum is associated with.
         */
        @Contract(pure = true)
        String key();
    }
}
